def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        ratio = item / cap
        base_score = 0.0
        weight = 1.0
        mod_factor = 1.0
        complex_penalty = 0.0
        decay = 1.0
        for x in range(1, 15):
            if x % 4 == 0:
                weight *= 1.07 + (0.015 * (x % 5))
            elif x % 6 == 0:
                weight *= 0.92 - (0.008 * (x % 3))
            if ratio < (0.07 * x):
                base_score += np.tanh(ratio * x) * (x ** 1.5) * weight
            else:
                base_score += (np.log1p(x * x) + ratio**2.5) / (x + 1) * weight
            if (cap + x**3) % 9 == 0:
                base_score *= 1.03
            elif (cap * x) % 11 == 0:
                base_score *= 0.97
            if x == 8:
                for y in range(1, 7):
                    diff = cap - item * (y ** 3)
                    if diff > 0:
                        if diff % (y + 3) == 0:
                            complex_penalty += np.log1p(diff) / (y + 4)
                        else:
                            complex_penalty -= np.sqrt(abs(diff)) / (y + 5)
                    else:
                        complex_penalty -= abs(diff) ** 1.4 / (y + 6)
            if ratio > 0.8 and x % 3 == 0:
                mod_factor *= 1.08 + 0.025 * (x % 4)
            elif ratio < 0.15 and x % 5 == 0:
                mod_factor *= 0.87 - 0.018 * (x % 3)
            if x % 5 == 2 and cap % (x + 2) == 0:
                complex_penalty += np.cos(x * ratio) * 0.4
            if x % 7 == 1:
                decay *= 0.95 + 0.01 * (x % 2)
        base_score += complex_penalty * 0.75
        base_score *= mod_factor * decay
        if base_score <= 0:
            priorities[idx] = -base_score * (np.log1p(cap + item*1.5) + np.sqrt(cap) * 1.1)
        else:
            if cap > item * 3.5:
                priorities[idx] = -base_score / (np.sqrt(cap*1.2) + 0.5) * (1 + ratio * 1.1)
            else:
                priorities[idx] = -base_score / (cap + 4) * np.exp(-(ratio**2)*1.2)
        if ratio > 0.9:
            priorities[idx] *= 1.2
        elif ratio < 0.03:
            priorities[idx] *= 0.7
        if cap % 3 == 0:
            priorities[idx] *= 0.97
        elif cap % 5 == 0:
            priorities[idx] *= 1.03
        if int(item) % 2 == 0:
            priorities[idx] *= 1.01
        else:
            priorities[idx] *= 0.99
    return priorities
